column6:
{
  "note": "You need close substitutions for sriracha that are commonly found in North American grocery stores.",
  "alts": [
    {
      "name_en": "Huy Fong Foods Chili Garlic Sauce (Sriracha)",
      "match": "Very close",
      "desc": "This is the most direct alternative because it’s the classic sriracha-style chili garlic sauce from the same original brand category.",
      "where": "International/Asian aisle, hot sauce or condiment shelf near sriracha"
    },
    {
      "name_en": "Lee Kum Kee Chili Garlic Sauce",
      "match": "Similar",
      "desc": "A chili-garlic hot sauce with a comparable sweet-savory heat profile that works well as a sriracha swap in recipes.",
      "where": "International/Asian aisle, condiment shelf (near other chili sauces)"
    },
    {
      "name_en": "Thai Kitchen Sweet Chili Sauce",
      "match": "Similar",
      "desc": "A sweet-heat chili sauce that’s different in flavor intensity but can substitute for sriracha in dressings, marinades, and dipping.",
      "where": "International/Asian aisle, bottled sauces and marinades section"
    },
    {
      "name_en": "Gochujang (Korean chili paste) + a splash of vinegar (as a sriracha-style drizzle)",
      "match": "Different but works",
      "desc": "Gochujang is thicker and sweeter but can mimic sriracha’s spicy-sauce function when thinned with vinegar for drizzling.",
      "where": "International/Asian aisle, Korean/Japanese pantry items (gochujang section) or refrigerated sauce area"
    }
  ]
}

{
  "note": "Lactose intolerance requires butter substitutes that are lactose-free (or non-dairy) and sold in North American grocery stores.",
  "alts": [
    {
      "name_en": "I Can’t Believe It’s Not Butter! Lactose-Free",
      "match": "Similar",
      "desc": "A lactose-free spread designed to taste and behave like butter while avoiding lactose.",
      "where": "Dairy/butter aisle near other spreads and lactose-free products"
    },
    {
      "name_en": "Smart Balance Lactose-Free Butter Blend",
      "match": "Similar",
      "desc": "A lactose-free butter blend that aims for a similar flavor and spreadability without lactose.",
      "where": "Dairy/butter aisle near spreads and lactose-free items"
    },
    {
      "name_en": "Kerrygold Butter (Lactose-Free or Lactose-Reduced option if available)",
      "match": "Similar",
      "desc": "Some brands offer lactose-reduced or lactose-free butter varieties that can be closest to traditional butter taste.",
      "where": "Specialty dairy section or near the butter case where lactose-free items are stocked"
    },
    {
      "name_en": "Plant-based butter (e.g., Earth Balance Original or similar lactose-free brands)",
      "match": "Different but works",
      "desc": "Non-dairy plant-based spreads are naturally lactose-free and work for many uses where butter is needed.",
      "where": "Vegan/plant-based aisle or dairy-free spread section"
    }
  ]
}

{
  "note": "To substitute rice vinegar with equivalent pantry staples commonly found in North American grocery stores.",
  "alts": [
    {
      "name_en": "Unseasoned Distilled White Vinegar",
      "match": "Similar",
      "desc": "High-acid vinegar that works for pickling, marinades, and quick tang in place of rice vinegar, though it lacks the mild sweetness/body.",
      "where": "Vinegar aisle, near other cooking vinegars (distilled/white vinegar)."
    },
    {
      "name_en": "Champagne Vinegar",
      "match": "Similar",
      "desc": "Milder and slightly fruity than white vinegar and can mimic rice vinegar’s gentle tang in dressings, quick pickles, and sauces.",
      "where": "Vinegar aisle, often in the specialty vinegar section."
    },
    {
      "name_en": "Apple Cider Vinegar (Unfiltered/Unseasoned)",
      "match": "Similar",
      "desc": "Provides comparable acidity and a softer flavor profile; it’s a good swap but can add a light apple note.",
      "where": "Vinegar aisle, near other apple cider vinegars."
    },
    {
      "name_en": "Mirin (Aji-mirin) or Seasoned Rice Vinegar",
      "match": "Different but works",
      "desc": "Mirin is sweeter and less purely acidic than rice vinegar, so it works better for sweet-sour sauces and glazing than for strict tang.",
      "where": "International/Japanese aisle (mirin) or condiment aisle (seasoned rice vinegar)."
    }
  ]
}

{
  "note": "You asked for vegetarian-safe alternatives to chicken breast found in North American stores.",
  "alts": [
    {
      "name_en": "Seitan (Wheat Gluten) Cutlets",
      "match": "Similar",
      "desc": "Seitan has a meaty, chewy texture that works well in slices, strips, or cutlets for stir-fries and sandwiches.",
      "where": "Produce/Prepared foods or refrigerated meat-alternative section near tofu/tempeh; sometimes in the vegan deli section"
    },
    {
      "name_en": "Tofu (Extra-Firm) Cutlets",
      "match": "Similar",
      "desc": "Extra-firm tofu can be pressed and cooked to mimic the firmness of chicken breast in many recipes.",
      "where": "Refrigerated tofu aisle (near other tofu varieties) in the grocery store"
    },
    {
      "name_en": "Tempeh",
      "match": "Similar",
      "desc": "Tempeh’s dense texture and ability to absorb marinades make it a practical chicken-breast stand-in for pan-searing or baking.",
      "where": "Refrigerated section near tofu/plant-based proteins"
    },
    {
      "name_en": "Plant-Based Chicken Breast Style Products (e.g., Soy/Pea Protein)",
      "match": "Different but works",
      "desc": "These products are designed to resemble chicken breast and can substitute in most meal types, though they’re not identical to meat.",
      "where": "Frozen or refrigerated meat-alternative section (often labeled ‘chicken-style’ or ‘plant-based chicken’) "
    }
  ]
}

{
  "note": "Provide Korean-friendly substitutes for fish sauce commonly found in North American grocery stores.",
  "alts": [
    {
      "name_en": "Gochugaru (Korean chili flakes) + soy sauce + a pinch of sugar (DIY fish-sauce style seasoning)",
      "match": "Similar",
      "desc": "Not identical in umami profile, but this mix can mimic the savory-salty effect used in Korean cooking.",
      "where": "International/Korean aisle (gochugaru) and condiments aisle (soy sauce) or at the condiment station"
    },
    {
      "name_en": "Miso paste (shiro or awase) diluted with water",
      "match": "Similar",
      "desc": "Adds strong fermented umami that can stand in for fish-sauce depth in marinades and soups.",
      "where": "Asian foods aisle near tofu/ramen/miso products"
    },
    {
      "name_en": "Soy sauce + a small amount of Worcestershire sauce",
      "match": "Similar",
      "desc": "Worcestershire contributes fermented savory notes that approximate fish sauce’s roundness, especially in stir-fries.",
      "where": "Condiments aisle (soy sauce and Worcestershire together)"
    },
    {
      "name_en": "Vegetarian/vegan fish sauce (if available, such as Lee Kum Kee Vegetarian Fish Sauce or similar brand)",
      "match": "Different but works",
      "desc": "Uses plant-based ingredients to recreate fish-sauce flavor, working for Korean-style seasoning when you can’t use fish.",
      "where": "Asian foods aisle or specialty/health-food section; check vegan/vegetarian Asian condiments"
    }
  ]
}
